def _send_telegram(text):
    token   = os.environ.get("TELEGRAM_BOT_TOKEN",    "").strip()
    chat_id = (os.environ.get("TELEGRAM_ALERT_CHAT_ID", "").strip()
               or os.environ.get("AUTHORIZED_ID", "").strip())
