                "fields": "spend,actions,cost_per_action_type",
                "date_preset": "last_7d",
                "access_token": token,
            },
            timeout=15,
        )
        data = r.json().get("data", [])
        if not data:
            return jsonify({"info": "Sem dados nos últimos 7 dias", "raw": r.json()})
        row = data[0]
